object DungeonOverlayManager {
    private var windowManager: WindowManager? = null
    private var overlayView: FrameLayout? = null

    fun show(ctx: Context, type: String) {
        if (overlayView != null) return

        windowManager = ctx.getSystemService(Context.WINDOW_SERVICE) as WindowManager
        val layoutParams = WindowManager.LayoutParams().apply {
            type = WindowManager.LayoutParams.TYPE_ACCESSIBILITY_OVERLAY
            format = PixelFormat.TRANSLUCENT
            flags = WindowManager.LayoutParams.FLAG_NOT_FOCUSABLE or 
                    WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN or
                    WindowManager.LayoutParams.FLAG_WATCH_OUTSIDE_TOUCH
            width = WindowManager.LayoutParams.MATCH_PARENT
            height = WindowManager.LayoutParams.MATCH_PARENT
            gravity = Gravity.CENTER
        }

        overlayView = FrameLayout(ctx).apply {
            // We need to trick Compose into thinking it's in an Activity
            val composeView = ComposeView(ctx).apply {
                setContent {
                    // We reuse the exact same UI logic from LockdownActivity
                    // But we'll need a simplified version or a shared Composable
                    // For now, a high-level 'Access Denied' screen
                }
            }
            addView(composeView)
        }

        try {
            windowManager?.addView(overlayView, layoutParams)
            DebugLogger.log("GHOST_OVERLAY", "Accessibility Overlay Deployed: $type")
        } catch (e: Exception) {
            DebugLogger.log("GHOST_ERR", "Failed to add overlay: ${e.message}")
        }
    }

    fun hide() {
        overlayView?.let {
            try { windowManager?.removeView(it) } catch (e: Exception) {}
            overlayView = null
            DebugLogger.log("GHOST_OVERLAY", "Overlay Withdrawn")
        }
    }
}

